sql:
SELECT batch_id, batch_name, volume AS total_volume, gravity
FROM batches
WHERE yeast_strain = 'WLP019' AND brew_date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT b.batch_name, r.recipe_name
FROM batches b
JOIN recipes r ON b.recipe_id = r.recipe_id;

SELECT batch_id
FROM batches
WHERE batch_name LIKE 'Batch%' AND yeast_strain = 'Safale US-05';

SELECT event_id, value AS max_value
FROM metrics
WHERE value = (SELECT MAX(value) FROM metrics);

SELECT COUNT(*)
FROM batch_status
WHERE status = 'Packaged';

SELECT DISTINCT yeast_strain
FROM batches
WHERE batch_name LIKE '%Batch%';

SELECT AVG(volume) AS average_volume
FROM batches
WHERE brew_date > '2022-12-31';

SELECT b.*
FROM batches b
WHERE b.volume > (SELECT AVG(volume) FROM batches);

SELECT b.batch_name, r.recipe_name 
FROM batches AS b 
LEFT JOIN recipes AS r ON b.recipe_id = r.recipe_id;

SELECT batches.batch_name, batches.gravity, recipes.recipe_name
FROM batches
INNER JOIN recipes ON batches.recipe_id = recipes.recipe_id;

